#[derive(Clone, Copy)]
pub struct SystemMask { pub scripts: bool, pub physics: bool, pub audio: bool,
    pub animation: bool, pub gi: bool, pub shadows: bool } // walking_sim starts with gi/scripts=false

// What the shell hands in per frame and what it owns:
pub struct FrameCtx<'a> {
