// Side outputs the shell needs back for rendering (loop does NOT render):
#[derive(Default)]
pub struct FrameOutput { pub anim_splats: Vec<vox_core::types::GaussianSplat>,
    pub sun_dir: glam::Vec3, pub fixed_steps: u32 }

impl EngineLoop {
    pub fn new(config: vox_core::engine_runtime::EngineConfig) -> Self; // builds Rapier ground plane, audio backend init, GI cache, ShadowMapper(128) — mirrors EngineApp::new:425-516
    pub fn with_systems(mut self, mask: SystemMask) -> Self;

    // ONE explicit-ordered frame of SIMULATION (no window, no GPU, no render).
    pub fn step(&mut self, ctx: &FrameCtx) -> FrameOutput;

    // Sub-steps are PUBLIC so a shell can call them à la carte during migration:
    pub fn step_scripts(&mut self, dt: f32);                       // wraps runtime.tick(dt) + animation_system
    pub fn step_physics(&mut self, dt: f32);                       // physics.step() + ECS<-Rapier sync (engine_runner:1969-1987)
    pub fn step_audio(&mut self, dt: f32, listener_pos: glam::Vec3, listener_fwd: glam::Vec3); // :1990-2006
    pub fn drain_sound_commands(&mut self);                        // PlaySound dispatch :2008-2031
    pub fn step_gi(&mut self, splats: &[GaussianSplat], hour: f32) -> Vec<GaussianSplat>; // set_sky+propagate+apply :980-993
    pub fn step_shadows(&mut self, cam_pos: Vec3, cam_fwd: Vec3, hour: f32, splats: &[GaussianSplat]) -> Vec3; // :1063-1077, returns sun_dir
}

New types in vox_core::engine_runtime, additive (nothing removed):

```rust
// Ordering anchors the host hooks attach to. Wrapper systems run host
// systems registered at each label, in registration order.
#[derive(Clone, Copy, PartialEq, Eq, Hash, Debug)]
pub enum EnginePhase {
    PreSim,      // input->intent, AI/navmesh, camera intent
    FixedSim,    // (runs 0..N times) scripts already here; host physics step
    PostSim,     // sync physics->ECS transforms, script-cmd dispatch
    PreRender,   // GI propagate/apply, shadow update, gather, cull
}

// A host-side per-frame system living in vox_app. dt is frame dt for
// variable phases; FixedSim hooks get fixed_dt. Exclusive World access so
// it can read InputResource/CameraState/RenderBuffer and mutate components.
pub trait EngineSystem: Send + Sync {
    fn run(&mut self, world: &mut World, dt: f32);
    fn name(&self) -> &str { "engine_system" }
}

// Resource holding ordered host hooks per phase.
#[derive(Resource, Default)]
pub struct HostSystems {
    pub hooks: std::collections::HashMap<EnginePhase, Vec<Box<dyn EngineSystem>>>,
}

impl EngineRuntime {
    // EXISTING (unchanged): new(EngineConfig), spawn(&str)->EntityBuilder,
    //   register_script(name,factory), start(), stop(), tick(frame_dt)->bool,
    //   time_of_day()/set_time_of_day(f32), world (pub), stats (pub).

    // NEW: register a host system at a phase. Returns &mut self for chaining.
    pub fn add_system(&mut self, phase: EnginePhase, sys: impl EngineSystem + 'static) -> &mut Self;

    // NEW: push raw input each event (shells call instead of touching world directly).
    pub fn input_mut(&mut self) -> &mut crate::input::InputState; // -> InputResource.state

    // NEW: set camera each frame from shell (drives cull/GI/gather).
    pub fn set_camera(&mut self, position: Vec3, forward: Vec3, view_proj: Mat4);

    // NEW: read render output after tick.
    pub fn render_buffer(&self) -> &RenderBuffer; // splats + lights, already populated by gather
}
```

Internally `tick(frame_dt)` (currently engine_runtime.rs:674-724) becomes: build/cache a `Schedule` once; run a single `schedule.run(&mut world)`. The schedule registers, in order: wrapper_pre_sim -> [fixed loop: script_update, process_script_commands, physics_integration, physics_collision, wrapper_fixed_sim] -> wrapper_post_sim -> frustum_cull -> gather_splats -> wrapper_pre_render. Each `wrapper_*` is an exclusive system that drains `HostSystems.hooks[phase]` and calls `sys.run(world, dt)`. The fixed-loop count logic (accumulator @690-704) stays in `tick` driving how many times the FixedSim group runs.

