// crates/vox_app/src/engine_loop.rs  (exposed as vox_app::engine_loop)
use glam::Vec3;
use vox_core::types::GaussianSplat;
use vox_core::input::InputState;
use vox_core::engine_runtime::{EngineRuntime, EngineConfig};

/// Per-phase ordering vocabulary (documentation/anchor names borrowed from #2;
/// the loop runs them in this fixed order inside `step`). Not a scheduler — just
/// stable names so call sites and tests describe WHEN work happens.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum EnginePhase { Scripts, Physics, Audio, Gi, Shadows }

/// Opt-out flags so a shell can share code paths without adopting new behavior.
/// walking_sim starts with gi=false, scripts=false (it has neither today).
#[derive(Clone, Copy, Debug)]
pub struct SystemMask {
    pub scripts: bool, pub physics: bool, pub audio: bool,
    pub animation: bool, pub gi: bool, pub shadows: bool,
}
impl SystemMask {
    pub fn all() -> Self { Self { scripts:true, physics:true, audio:true, animation:true, gi:true, shadows:true } }
    pub fn game_minimal() -> Self { Self { scripts:false, physics:true, audio:true, animation:true, gi:false, shadows:true } }
}

/// Typed cross-substep blackboard (grafted from #3) so sub-steps share the
/// render-splat list / listener pose without a god-struct or extra clones.
/// Single-threaded loop, so no Send bound is required on stored values.
#[derive(Default)]
pub struct Blackboard { map: std::collections::HashMap<std::any::TypeId, Box<dyn std::any::Any>> }
impl Blackboard {
    pub fn new() -> Self { Self::default() }
    pub fn insert<T: 'static>(&mut self, v: T) { self.map.insert(std::any::TypeId::of::<T>(), Box::new(v)); }
    pub fn get<T: 'static>(&self) -> Option<&T> { self.map.get(&std::any::TypeId::of::<T>()).and_then(|b| b.downcast_ref()) }
    pub fn get_mut<T: 'static>(&mut self) -> Option<&mut T> { self.map.get_mut(&std::any::TypeId::of::<T>()).and_then(|b| b.downcast_mut()) }
}

/// What the shell hands in each frame. Camera passed BY VALUE (Vec3 copies) to
/// avoid borrow friction with the shell's &mut self (risk #5 in #1).
pub struct FrameCtx<'a> {
    pub dt: f32,
    pub input: &'a InputState,
    pub camera_pos: Vec3,
    pub camera_fwd: Vec3,
    pub hour: f32,            // time-of-day 0..24, drives GI sky + shadow sun
}

/// Side outputs the shell needs back for its own rendering (loop never renders).
#[derive(Default)]
pub struct FrameOutput {
    pub anim_splats: Vec<GaussianSplat>, // drained from RenderBuffer (mem::take)
    pub sun_dir: Vec3,
    pub fixed_steps: u32,
}

pub struct EngineLoop {
    pub runtime: EngineRuntime, // existing vox_core ECS — UNTOUCHED, composed not replaced
    pub physics: vox_physics::rapier::RapierPhysicsWorld,
    pub audio: vox_audio::AudioEngine,
    pub spatial_audio: vox_audio::spatial::SpatialAudioManager,
    pub shadow_mapper: vox_render::shadows::ShadowMapper,
    pub spectral_atmosphere: vox_render::spectral_atmosphere::SpectralAtmosphere,
    pub spectral_gi: vox_render::spectral_gi::SpectralRadianceCache,
    /// Pure-sim ECS<->Rapier maps relocated off the shell (risk #2 in #1).
    pub entity_rapier_bodies: std::collections::HashMap<u32, vox_physics::RigidBodyHandle>,
    pub mask: SystemMask,
    pub blackboard: Blackboard,
}

impl EngineLoop {
    /// Mirrors EngineApp::new 425-516: Rapier ground plane, audio backend init,
    /// GI cache, ShadowMapper, earth atmosphere. Does NOT create window/GPU.
    pub fn new(config: EngineConfig, mask: SystemMask) -> Self;
    pub fn with_mask(mut self, mask: SystemMask) -> Self;

    /// ONE explicit-ordered SIMULATION frame (no window, no GPU, no render).
    /// Runs enabled phases in EnginePhase order: Scripts -> Physics -> Audio.
    /// GI/Shadows are NOT in step() because they need the shell's post-cull
    /// render-splat list; the shell calls step_gi/step_shadows from render_frame.
    pub fn step(&mut self, ctx: &FrameCtx) -> FrameOutput;

    // Sub-steps PUBLIC so shells call them a la carte during migration:
    pub fn step_scripts(&mut self, dt: f32);                 // runtime.tick(dt) + animation_system drain -> blackboard
    pub fn step_physics(&mut self, dt: f32);                 // physics.step() + ECS<-Rapier sync (engine_runner 1969-1987)
    pub fn step_audio(&mut self, dt: f32, listener_pos: Vec3, listener_fwd: Vec3); // 1990-2006
    pub fn drain_sound_commands(&mut self);                  // PlaySound dispatch 2008-2031
    pub fn step_gi(&mut self, splats: &[GaussianSplat], hour: f32) -> Vec<GaussianSplat>; // set_sky+propagate(.,256)+apply 980-993
    pub fn step_shadows(&mut self, cam_pos: Vec3, cam_fwd: Vec3, hour: f32, splats: &[GaussianSplat]) -> Vec3; // 1063-1077 -> sun_dir

    // Re-exposed for shells that read engine state inline today:
    pub fn world(&mut self) -> &mut bevy_ecs::world::World { &mut self.runtime.world }
    pub fn time_of_day(&self) -> f32 { self.runtime.time_of_day() }
    pub fn set_time_of_day(&mut self, h: f32) { self.runtime.set_time_of_day(h); }
}
// NOTE: Rhai/Lua per-frame drain (engine_runner 2033-2080) is NOT in EngineLoop's
// signature above because it touches process-GLOBAL state (rhai drain_pending_commands,
// risk #4) and the two shells differ; it stays an editor-shell concern behind mask.scripts,
// optionally added later as step_script_hooks() once a single owner is decided.
